import{_ as e,o as r,c as t,a2 as i}from"./chunks/framework.DIMps2S2.js";const p=JSON.parse('{"title":"电汇出金","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"withdrawal/wire-transfer.md","filePath":"zh-CN/withdrawal/wire-transfer.md"}'),l={name:"withdrawal/wire-transfer.md"};function o(h,a,n,d,s,c){return r(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="电汇出金" tabindex="-1">电汇出金 <a class="header-anchor" href="#电汇出金" aria-label="Permalink to &quot;电汇出金&quot;">​</a></h1><p>电汇出金适用于非香港银行卡用户，资金从长桥汇出银行（工银亚洲）通过国际电汇转至客户的境外银行账户。</p><h2 id="支持币种" tabindex="-1">支持币种 <a class="header-anchor" href="#支持币种" aria-label="Permalink to &quot;支持币种&quot;">​</a></h2><p>港元（HKD）、美元（USD）</p><h2 id="到账时间" tabindex="-1">到账时间 <a class="header-anchor" href="#到账时间" aria-label="Permalink to &quot;到账时间&quot;">​</a></h2><p>申请提款后 1-2 个工作日汇出资金，因涉及资金跨境中转，具体到账时间不确定，预计 3-7 个工作日。请留意收款银行到账通知。</p><h2 id="手续费" tabindex="-1">手续费 <a class="header-anchor" href="#手续费" aria-label="Permalink to &quot;手续费&quot;">​</a></h2><p>长桥不收费。<br> 汇出银行固定收取 140 港币，另加中转银行收费约 25 美元（涉及收款银行、中转银行会有所不同）。<br> 请以实际到账金额为准。</p><h2 id="操作流程" tabindex="-1">操作流程 <a class="header-anchor" href="#操作流程" aria-label="Permalink to &quot;操作流程&quot;">​</a></h2><p>长桥 App - 资产 - 全部功能 - 提取资金，选择币种和非香港银行卡，提交出金申请。</p><h2 id="大额出金" tabindex="-1">大额出金 <a class="header-anchor" href="#大额出金" aria-label="Permalink to &quot;大额出金&quot;">​</a></h2><p>单笔提取金额超过 100 万 HKD / 15 万 USD 需人工审批，请提前做好安排。</p><h2 id="同名账户、大额审批与费用说明" tabindex="-1">同名账户、大额审批与费用说明 <a class="header-anchor" href="#同名账户、大额审批与费用说明" aria-label="Permalink to &quot;同名账户、大额审批与费用说明&quot;">​</a></h2><ul><li>提取资金银行账户名必须与长桥证券账户名同名，资金不能提取到他人账户、第三方支付平台或联名银行账户</li><li>提交材料认证但未入金时不允许出金</li><li>汇款费用如有变更恕不另行通知，汇款银行、收款银行及中间银行产生的费用均由客户承担</li><li>节假日及休市期间银行不处理资金业务，可能影响到账时间</li><li>只有账户拥有充足的可用资金，取款请求才会被处理</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/withdrawal">出金</a></li></ul>',16)])])}const f=e(l,[["render",o]]);export{p as __pageData,f as default};
